// ============================================================
// INJECTION LOGIC
// ============================================================

// Map of page namespace to the JSON namespace key
const nsMap = {
  estimation: 'estimation',
  fraisAcquisition: 'fraisAcquisition',
  calculLoyer: 'calculLoyer',
  simulateurAides: 'simulateurAides',
  plusValues: 'plusValues',
  achatVsLocation: 'achatLocation',  // Note: the JSON key is 'achatLocation'
  comparer: 'comparer',
  vefa: 'vefa'
};

const langMap = {
  fr: 'fr',
  en: 'en',
  de: 'de',
  pt: 'pt',
  lb: 'lb'
};

for (const lang of LANGS) {
  const filePath = `${MESSAGES_DIR}/${lang}.json`;
  console.log(`Processing ${filePath}...`);

  const raw = readFileSync(filePath, 'utf-8');
  const data = JSON.parse(raw);

  for (const [seoKey, translations] of Object.entries(seoData)) {
    const jsonNs = nsMap[seoKey];
    if (!jsonNs) {
      console.error(`No JSON namespace mapping for ${seoKey}`);
      continue;
    }

    if (!data[jsonNs]) {
      console.error(`Namespace ${jsonNs} not found in ${lang}.json`);
      continue;
    }

    const langTranslations = translations[lang];
    if (!langTranslations) {
      console.error(`No ${lang} translations for ${seoKey}`);
      continue;
    }

    // Add seo sub-object
    data[jsonNs].seo = langTranslations;
    console.log(`  Added ${Object.keys(langTranslations).length} SEO keys to ${jsonNs}.seo`);
  }

  // Write back with proper formatting
  writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n', 'utf-8');
  console.log(`  Saved ${filePath}`);
}

console.log('\nDone! All SEO translations injected.');
